import asyncio, logging
logging.basicConfig\(level=logging.WARNING\)

async def run\(\):
    from apps.crawler.src.scrapers.mf_sbi_bank import MFSBIScraper
    scraper = MFSBIScraper\(headless=True\)
    try:
        await scraper.__aenter__\(\)
        await scraper.login\(\)
        # ホームページで一括更新ボタンを探す（別ページの可能性）
        await scraper._page.goto\('https://ssnb.x.moneyforward.com/', wait_until='networkidle'\)

        result = await scraper._page.evaluate\('''\(\) => {
            const all = document.querySelectorAll\('a, button'\);
            const results = [];
            for \(const el of all\) {
                const text = \(el.textContent || ''\).trim\(\);
                if \(text.length > 0 && text.length < 30\) {
                    results.push\({
                        tag: el.tagName,
                        class: el.className,
                        href: el.href || '',
                        text: text
                    }\);
                }
            }
            return results.slice\(0, 30\);
        }'''\)
        print\('=== ホームのリンク・ボタン（最初30件）==='\)
        for r in result:
            print\(f'  [{r[\\"text\\"]}] class={r[\\"class\\"][:30]} href={r[\\"href\\"][:50]}'\)
    finally:
        await scraper.__aexit__\(None, None, None\)

asyncio.run\(run\(\)\)
